import os
import sys
import hashlib
import json
from setuptools import setup, find_packages
from setuptools.command.install import install
import urllib.request
import ssl
import subprocess

TRUSTED_CONFIG_URL = "https://raw.githubusercontent.com/yourusername/yourrepo/main/dependencies.json"
EXPECTED_CONFIG_HASH = "put_your_expected_sha256_hash_here"

ALLOWED_PACKAGES = {
    "requests", "numpy", "pandas", "flask", "django", "pytest",
    "setuptools", "wheel", "pip", "certifi", "urllib3", "idna",
    "charset-normalizer", "click", "jinja2", "markupsafe", "werkzeug",
    "itsdangerous", "python-dateutil", "pytz", "six", "attrs"
}

MAX_DEPENDENCIES = 50
PACKAGE_NAME_MAX_LENGTH = 100

def verify_package_name(package_name):
    if not package_name:
        raise ValueError("Empty package name detected")
    
    base_name = package_name.split('[')[0].split('=')[0].split('<')[0].split('>')[0].split('!')[0].strip()
    
    if len(base_name) > PACKAGE_NAME_MAX_LENGTH:
        raise ValueError(f"Package name too long: {base_name}")
    
    if not all(c.isalnum() or c in '-_.' for c in base_name):
        raise ValueError(f"Invalid characters in package name: {base_name}")
    
    if base_name.lower() not in ALLOWED_PACKAGES:
        raise ValueError(f"Package not in allowlist: {base_name}")
    
    return True

def verify_hash(content, expected_hash):
    actual_hash = hashlib.sha256(content).hexdigest()
    if actual_hash != expected_hash:
        raise ValueError(f"Hash mismatch! Expected: {expected_hash}, Got: {actual_hash}")
    return True

def fetch_dependencies_config():
    try:
        context = ssl.create_default_context()
        context.check_hostname = True
        context.verify_mode = ssl.CERT_REQUIRED
        
        with urllib.request.urlopen(TRUSTED_CONFIG_URL, timeout=10, context=context) as response:
            content = response.read()
            
        verify_hash(content, EXPECTED_CONFIG_HASH)
        
        config = json.loads(content.decode('utf-8'))
        
        if not isinstance(config, dict):
            raise ValueError("Invalid config format")
        
        dependencies = config.get('dependencies', [])
        
        if not isinstance(dependencies, list):
            raise ValueError("Dependencies must be a list")
        
        if len(dependencies) > MAX_DEPENDENCIES:
            raise ValueError(f"Too many dependencies: {len(dependencies)}")
        
        validated_deps = []
        for dep in dependencies:
            if not isinstance(dep, str):
                raise ValueError(f"Invalid dependency format: {dep}")
            verify_package_name(dep)
            validated_deps.append(dep)
        
        return validated_deps
    
    except Exception as e:
        print(f"Warning: Could not fetch remote config: {e}", file=sys.stderr)
        print("Falling back to default dependencies", file=sys.stderr)
        return ["requests>=2.28.0,<3.0.0", "certifi>=2022.0.0"]

class SecureInstallCommand(install):
    def run(self):
        install.run(self)
        
        additional_packages = []
        
        if additional_packages:
            print("Installing additional packages with security checks...")
            for package in additional_packages:
                try:
                    verify_package_name(package)
                    
                    result = subprocess.run(
                        [sys.executable, "-m", "pip", "install", 
                         "--no-cache-dir", 
                         "--require-hashes",
                         "--only-binary", ":all:",
                         package],
                        capture_output=True,
                        text=True,
                        timeout=300
                    )
                    
                    if result.returncode != 0:
                        print(f"Warning: Failed to install {package}: {result.stderr}", file=sys.stderr)
                
                except Exception as e:
                    print(f"Error installing {package}: {e}", file=sys.stderr)

dependencies = fetch_dependencies_config()

